import { useHistory } from 'react-router-dom'; // Cambia useNavigate por useHistory

import stonesImg from '../assets/img/stones.png';
import sulfurOreImg from '../assets/img/sulfur.ore.png';
import hqMetalOreImg from '../assets/img/hq.metal.ore.png';
import metalOreImg from '../assets/img/metal.ore.png';
import woodImg from '../assets/img/wood.png';

const Events = () => {
    const history = useHistory();
    const [table, setTable] = React.useState('PlayerStats');
    const [rows, setRows] = React.useState([]);
    const [columns, setColumns] = React.useState([]);
    const [loading, setLoading] = React.useState(true);
    const [error, setError] = React.useState('');
    const [selectedPlayer, setSelectedPlayer] = React.useState(null);
    const [playerDetail, setPlayerDetail] = React.useState(null);
    const [detailLoading, setDetailLoading] = React.useState(false);
    const [detailError, setDetailError] = React.useState('');

    const headerMeta = {
        Rank: { label: '#', icon: 'trophy' },
        UserId: { label: 'UserId', icon: 'person-badge' },
        LastName: { label: 'Nickname', icon: 'person' },
        Kills: { label: 'Kills', icon: 'crosshair' },
        Deaths: { label: 'Deaths', icon: 'skull' },
        KDR: { label: 'KDR', icon: 'bar-chart' },
        Points: { label: 'Points', icon: 'stars' },
        TotalPlayTime: { label: 'Play Time', icon: 'clock' },
        ShortName: { label: 'Short Name', icon: 'tag' },
        LootType: { label: 'Loot Type', icon: 'boxes' },
        ItemValue: { label: 'Value', icon: 'hash' }
    };

    const columnOrder = {
        PlayerStats: ['Rank', 'LastName', 'Kills', 'Deaths', 'KDR', 'Points'],
        StatsStorage: ['UserId', 'LootType', 'ShortName', 'ItemValue']
    };

    const resourceMeta = {
        stones: { label: 'Stone', image: stonesImg },
        'sulfur.ore': { label: 'Sulfur Ore', image: sulfurOreImg },
        'hq.metal.ore': { label: 'HQ Metal Ore', image: hqMetalOreImg },
        'metal.ore': { label: 'Metal Ore', image: metalOreImg },
        wood: { label: 'Wood', image: woodImg }
    };

    const openPlayerDetail = async (row) => {
        const userIdFromRow = String(row?.UserId || '').trim();
        const nameFromRow = String(row?.LastName || '').trim();
        const isNumericId = (value) => /^[0-9]{5,20}$/.test(value);
        const userId = isNumericId(userIdFromRow)
            ? userIdFromRow
            : (isNumericId(nameFromRow) ? nameFromRow : '');
        if (!userId) return;
        setSelectedPlayer(row);
        setPlayerDetail(null);
        setDetailError('');
        setDetailLoading(true);
        try {
            const nickname = nameFromRow;
            const response = await fetch(
                `/api/player-stats?userId=${encodeURIComponent(userId)}&nickname=${encodeURIComponent(nickname)}`
            );
            if (!response.ok) {
                throw new Error('Player stats request failed');
            }
            const data = await response.json();
            setPlayerDetail(data);
        } catch (err) {
            setDetailError('No se pudieron cargar las estadisticas del jugador.');
        } finally {
            setDetailLoading(false);
        }
    };

    React.useEffect(() => {
        let isActive = true;
        const loadStats = async () => {
            setLoading(true);
            setError('');
            try {
                const response = await fetch(`/api/stats?table=${encodeURIComponent(table)}&limit=50`);
                if (!response.ok) {
                    throw new Error('Stats request failed');
                }
                const data = await response.json();
                let nextRows = Array.isArray(data.rows) ? data.rows : [];
                let nextColumns = nextRows[0] ? Object.keys(nextRows[0]) : [];
                if (table === 'PlayerStats') {
                    const hiddenColumns = new Set([
                        'UserId',
                        'LastIP',
                        'ConnectTime',
                        'DisconnectTime',
                        'TotalPlayTime',
                        'Points',
                        'HiddenFromLeaderboard'
                    ]);
                    nextColumns = nextColumns.filter((col) => !hiddenColumns.has(col));
                    nextRows = [...nextRows].sort((a, b) => Number(b.Kills || 0) - Number(a.Kills || 0));
                    nextColumns = ['Rank', ...nextColumns];
                    setSelectedPlayer(null);
                    setPlayerDetail(null);
                }
                if (columnOrder[table]) {
                    const order = columnOrder[table];
                    const ordered = order.filter((col) => nextColumns.includes(col));
                    const remaining = nextColumns.filter((col) => !order.includes(col));
                    nextColumns = [...ordered, ...remaining];
                }
                if (isActive) {
                    setRows(nextRows);
                    setColumns(nextColumns);
                }
            } catch (err) {
                if (isActive) {
                    setError('No se pudieron cargar las estadisticas.');
                    setRows([]);
                    setColumns([]);
                }
            } finally {
                if (isActive) {
                    setLoading(false);
                }
            }
        };

        loadStats();
        return () => {
            isActive = false;
        };
    }, [table]);

    return (
        <div
            style={{
                maxWidth: 1000,
                margin: '4rem auto',
                background: 'rgba(24,24,24,0.97)',
                borderRadius: 24,
                boxShadow: '0 8px 32px #000b',
                padding: '2.5rem 2rem',
                textAlign: 'center',
                fontFamily: 'Montserrat, Arial, sans-serif',
                color: '#fff',
                position: 'relative'
            }}
        >
            <h1
                style={{
                    color: 'var(--rust-orange)',
                    fontWeight: 900,
                    fontSize: '2.2rem',
                    marginBottom: '1.5rem',
                    letterSpacing: '2px',
                    textShadow: '0 2px 18px #000a'
                }}
            >
                Estadisticas del Evento
            </h1>
            <div style={{
                display: 'flex',
                justifyContent: 'center',
                gap: 12,
                marginBottom: '1.6rem',
                flexWrap: 'wrap',
                position: 'relative'
            }}>
                <button
                    type="button"
                    onClick={() => setTable('PlayerStats')}
                    style={{
                        padding: '0.6rem 1.6rem',
                        borderRadius: 10,
                        border: '1px solid #e25822aa',
                        background: table === 'PlayerStats' ? '#e25822' : '#23201a',
                        color: '#fff',
                        fontWeight: 700,
                        cursor: 'pointer'
                    }}
                >
                    PlayerStats
                </button>
                <button
                    type="button"
                    onClick={() => setTable('StatsStorage')}
                    style={{
                        padding: '0.6rem 1.6rem',
                        borderRadius: 10,
                        border: '1px solid #e25822aa',
                        background: table === 'StatsStorage' ? '#e25822' : '#23201a',
                        color: '#fff',
                        fontWeight: 700,
                        cursor: 'pointer'
                    }}
                >
                    StatsStorage
                </button>
            </div>

            {loading && (
                <div style={{
                    padding: '1.2rem 1rem',
                    color: '#b3cfff',
                    fontWeight: 600
                }}>
                    Cargando estadisticas...
                </div>
            )}

            {!loading && error && (
                <div style={{
                    background: 'rgba(226,88,34,0.18)',
                    borderRadius: 14,
                    padding: '1rem',
                    marginBottom: '1.2rem',
                    border: '1px solid #e25822aa'
                }}>
                    {error}
                </div>
            )}

            {!loading && !error && rows.length === 0 && (
                <div style={{
                    background: 'rgba(34,34,34,0.97)',
                    borderRadius: 14,
                    padding: '1rem',
                    marginBottom: '1.2rem'
                }}>
                    Sin registros por ahora.
                </div>
            )}

            {!loading && !error && rows.length > 0 && (
                <div style={{
                    overflowX: 'auto',
                    borderRadius: 16,
                    border: '1px solid rgba(255,255,255,0.12)',
                    boxShadow: '0 12px 30px rgba(0,0,0,0.45)',
                    position: 'relative'
                }}>
                    <table style={{
                        width: '100%',
                        borderCollapse: 'collapse',
                        textAlign: 'left',
                        fontSize: '0.95rem'
                    }}>
                        <thead>
                            <tr style={{ background: 'rgba(28,24,20,0.95)' }}>
                                {columns.map((col) => (
                                    <th key={col} style={{
                                        padding: '0.75rem 0.9rem',
                                        borderBottom: '1px solid rgba(255,255,255,0.1)',
                                        color: '#f5d7c1'
                                    }}>
                                        <span style={{ display: 'inline-flex', alignItems: 'center', gap: 8 }}>
                                            {headerMeta[col]?.icon && (
                                                <i className={`bi bi-${headerMeta[col].icon}`} aria-hidden="true" />
                                            )}
                                            <span>{headerMeta[col]?.label || col}</span>
                                        </span>
                                    </th>
                                ))}
                            </tr>
                        </thead>
                        <tbody>
                            {rows.map((row, idx) => (
                                <tr key={idx} style={{
                                    background: idx % 2 === 0 ? 'rgba(20,20,22,0.95)' : 'rgba(28,28,30,0.95)'
                                }}>
                                    {columns.map((col) => (
                                        <td key={`${idx}-${col}`} style={{
                                            padding: '0.65rem 0.9rem',
                                            borderBottom: '1px solid rgba(255,255,255,0.06)',
                                            color: '#fff'
                                        }}>
                                            {table === 'PlayerStats' && col === 'Rank' ? (
                                                <span style={{
                                                    color: '#f5d7c1',
                                                    fontWeight: 700
                                                }}>
                                                    {idx + 1}
                                                </span>
                                            ) : table === 'PlayerStats' && col === 'LastName' ? (
                                                <button
                                                    type="button"
                                                    onClick={() => openPlayerDetail(row)}
                                                    style={{
                                                        background: 'transparent',
                                                        border: 'none',
                                                        padding: 0,
                                                        color: '#b3cfff',
                                                        fontWeight: 700,
                                                        cursor: 'pointer',
                                                        textDecoration: 'underline'
                                                    }}
                                                >
                                                    {String(row[col] ?? '')}
                                                </button>
                                            ) : (
                                                String(row[col] ?? '')
                                            )}
                                        </td>
                                    ))}
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}
            {selectedPlayer && (
                <div
                    role="presentation"
                    onClick={() => setSelectedPlayer(null)}
                    style={{
                        position: 'fixed',
                        inset: 0,
                        background: 'rgba(10,10,10,0.75)',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        zIndex: 2000,
                        padding: '1.2rem'
                    }}
                >
                    <div
                        role="dialog"
                        aria-modal="true"
                        onClick={(event) => event.stopPropagation()}
                        style={{
                            width: 'min(900px, 95vw)',
                            maxHeight: '90vh',
                            overflowY: 'auto',
                            background: 'linear-gradient(140deg, rgba(18,18,20,0.98), rgba(40,28,18,0.98))',
                            borderRadius: 24,
                            border: '1px solid rgba(255,255,255,0.1)',
                            boxShadow: '0 16px 48px rgba(0,0,0,0.6)',
                            padding: '1.8rem 2rem',
                            color: '#fff'
                        }}
                    >
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                            <h2 style={{ margin: 0, fontSize: '1.7rem', letterSpacing: '1px' }}>
                                {playerDetail?.player?.LastName || selectedPlayer.LastName || 'Jugador'}
                            </h2>
                            <button
                                type="button"
                                onClick={() => setSelectedPlayer(null)}
                                style={{
                                    background: '#e25822',
                                    border: 'none',
                                    color: '#fff',
                                    fontWeight: 700,
                                    borderRadius: 10,
                                    padding: '0.4rem 0.9rem',
                                    cursor: 'pointer'
                                }}
                            >
                                Cerrar
                            </button>
                        </div>

                        {detailLoading && (
                            <div style={{ marginTop: '1rem', color: '#b3cfff' }}>Cargando stats...</div>
                        )}

                        {!detailLoading && detailError && (
                            <div style={{
                                marginTop: '1rem',
                                background: 'rgba(226,88,34,0.18)',
                                padding: '0.8rem 1rem',
                                borderRadius: 12,
                                border: '1px solid rgba(226,88,34,0.5)'
                            }}>
                                {detailError}
                            </div>
                        )}

                        {!detailLoading && !detailError && playerDetail && (
                            <div style={{ marginTop: '1.2rem' }}>
                                <div style={{
                                    display: 'grid',
                                    gridTemplateColumns: 'repeat(auto-fit, minmax(160px, 1fr))',
                                    gap: '0.9rem'
                                }}>
                                    {[
                                        { label: 'Kills', value: playerDetail.player.Kills, icon: 'crosshair' },
                                        { label: 'Deaths', value: playerDetail.player.Deaths, icon: 'skull' },
                                        { label: 'KDR', value: playerDetail.player.KDR, icon: 'bar-chart' },
                                        { label: 'Points', value: playerDetail.player.Points, icon: 'stars' }
                                    ].map((item) => (
                                        <div key={item.label} style={{
                                            background: 'rgba(24,24,24,0.9)',
                                            borderRadius: 14,
                                            border: '1px solid rgba(255,255,255,0.08)',
                                            padding: '0.8rem 1rem'
                                        }}>
                                            <div style={{
                                                color: '#f5d7c1',
                                                fontWeight: 700,
                                                display: 'flex',
                                                alignItems: 'center',
                                                gap: 8
                                            }}>
                                                <i className={`bi bi-${item.icon}`} aria-hidden="true" />
                                                {item.label}
                                            </div>
                                            <div style={{ fontSize: '1.2rem', marginTop: 6 }}>
                                                {String(item.value ?? 0)}
                                            </div>
                                        </div>
                                    ))}
                                </div>

                                <div style={{ marginTop: '1.6rem' }}>
                                    <h3 style={{ marginBottom: '0.8rem', color: '#f5d7c1' }}>
                                        Resources
                                    </h3>
                                    {playerDetail.resources.length === 0 ? (
                                        <div style={{ color: '#b3cfff' }}>Sin recursos registrados.</div>
                                    ) : (
                                        <div style={{
                                            display: 'grid',
                                            gridTemplateColumns: 'repeat(auto-fit, minmax(160px, 1fr))',
                                            gap: '0.75rem'
                                        }}>
                                            {['sulfur.ore', 'stones', 'metal.ore', 'hq.metal.ore', 'wood']
                                                .map((shortName) => {
                                                    const resource = playerDetail.resources.find(
                                                        (item) => item.ShortName === shortName
                                                    );
                                                    const meta = resourceMeta[shortName];
                                                    return {
                                                        ShortName: shortName,
                                                        label: meta?.label || shortName,
                                                        image: meta?.image || '',
                                                        ItemValue: resource ? resource.ItemValue : 0
                                                    };
                                                })
                                                .map((resource) => (
                                                    <div key={resource.ShortName} style={{
                                                        background: 'rgba(24,24,24,0.9)',
                                                        borderRadius: 14,
                                                        border: '1px solid rgba(255,255,255,0.08)',
                                                        padding: '0.9rem 1rem',
                                                        display: 'flex',
                                                        alignItems: 'center',
                                                        justifyContent: 'space-between',
                                                        gap: 12,
                                                        minHeight: 64
                                                    }}>
                                                        <div
                                                            style={{
                                                                display: 'flex',
                                                                alignItems: 'center',
                                                                gap: 10,
                                                                color: '#f5d7c1',
                                                                fontWeight: 700
                                                            }}
                                                            aria-label={resource.label}
                                                            title={resource.label}
                                                        >
                                                            {resource.image ? (
                                                                <img
                                                                    src={resource.image}
                                                                    alt={resource.label}
                                                                    style={{ width: 28, height: 28, objectFit: 'contain' }}
                                                                />
                                                            ) : (
                                                                <span>{resource.label}</span>
                                                            )}
                                                        </div>
                                                        <div style={{
                                                            fontSize: '1.1rem',
                                                            fontWeight: 800,
                                                            color: '#fff'
                                                        }}>
                                                            {Number(resource.ItemValue || 0).toLocaleString()}
                                                        </div>
                                                    </div>
                                                ))}
                                        </div>
                                    )}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            )}
            <button
                onClick={() => history.push('/')}
                style={{
                    marginTop: '2.2rem',
                    background: 'linear-gradient(90deg, #e25822 60%, #23201a 100%)',
                    color: '#fff',
                    fontWeight: 700,
                    fontSize: '1.08rem',
                    padding: '0.8rem 2.2rem',
                    border: 'none',
                    borderRadius: 14,
                    boxShadow: '0 2px 12px #0007',
                    cursor: 'pointer',
                    transition: 'background 0.2s, transform 0.2s',
                    letterSpacing: '1px'
                }}
                onMouseOver={e => (e.currentTarget.style.transform = 'scale(1.07)')}
                onMouseOut={e => (e.currentTarget.style.transform = 'scale(1)')}
            >
                Volver al inicio
            </button>
        </div>
    );
};

export default Events;
